// Inside a classic ASP.NET MVC controller action (not ASP.NET Core):
public ActionResult Index()
{
    var data = LoadAsync().Result; // <-- hangs forever in production
    return View(data);
}

private async Task<string> LoadAsync()
{
    var client = new HttpClient();
    var response = await client.GetStringAsync("https://example.com");
    return response;
}

// Three ways to use a FileStream:

// (1) raw ÔÇö leaks on exception:
var fs1 = new FileStream("a.txt", FileMode.Open);
var b1 = new byte[16];
fs1.Read(b1, 0, 16);
fs1.Dispose();

// (2) classic using block:
using (var fs2 = new FileStream("a.txt", FileMode.Open))
{
    var b2 = new byte[16];
    fs2.Read(b2, 0, 16);
}

// (3) C# 8 using declaration:
using var fs3 = new FileStream("a.txt", FileMode.Open);
